// 3x3 WR 单次 + Ao5 历史. 主表自动生成于本地 WCA dump (running-min progression).
// 生成器: core/packages/stats-build/src/bin/wr333_history_build.ts
// 数据源: stats/prediction/wr333_history.json
// 手写注释 (STM / TPS / method / hardware / feature) 见 ./wr333_annotations.ts
// 复盘 (scramble + solution) 见 ./wr333_reconstructions.ts

// Local copy of stats/prediction/wr333_history.json. The original lives at the repo root
// (regenerated by core/packages/stats-build/src/bin/wr333_history_build.ts). Next dev
// can't easily import files outside the workspace tree (outputFileTracingRoot=core/),
// so we keep a synced copy here. If regenerating WRs, copy the file over again.
import rawData from './wr333_history.json';
import { SINGLE_ANNOTATIONS, AO5_ANNOTATIONS, type WrAnnotation } from './wr333_annotations';

export interface WrSingle extends WrAnnotation {
  date: string;
  time: number;
  holder: string;
  country: string;
  comp: string;
  comp_id: string;
}

export interface WrAo5 extends WrAnnotation {
  date: string;
  time: number;
  holder: string;
  country: string;
  comp: string;
  comp_id: string;
  solves?: number[];
}

interface RawRow {
  date: string;
  time: number;
  holder: string;
  country: string;
  comp: string;
  comp_id: string;
}

interface RawSub {
  threshold: number;
  date: string;
  holder: string;
  country: string;
  comp: string;
  value: number;
}

interface RawData {
  generated_at: string;
  notes: string;
  singles: RawRow[];
  ao5: RawRow[];
  subMilestonesSingle: RawSub[];
  subMilestonesAo5: RawSub[];
}

const data = rawData as RawData;

function merge<T extends RawRow>(rows: T[], annos: Record<string, WrAnnotation>): (T & WrAnnotation)[] {
  return rows.map((r) => ({ ...r, ...(annos[`${r.date}-${r.holder}`] ?? {}) }));
}

export const WR_SINGLE_HISTORY: WrSingle[] = merge(data.singles, SINGLE_ANNOTATIONS);
export const WR_AO5_HISTORY: WrAo5[] = merge(data.ao5, AO5_ANNOTATIONS);

export interface SubMilestone {
  threshold: number;
  year: number;
  date: string;
  holder: string;
  country: string;
  comp: string;
  value: number;
  note_en: string;
  note_zh: string;
}

function annotateSub(rows: RawSub[], kind: 'single' | 'ao5'): SubMilestone[] {
  return rows.map((r) => {
    const year = Number(r.date.slice(0, 4));
    const label = kind === 'single' ? 'single' : 'Ao5';
    const labelZh = kind === 'single' ? '单次' : 'Ao5';
    return {
      ...r,
      year,
      note_en: `first sub-${r.threshold} ${label} (${r.value.toFixed(2)})`,
      note_zh: `首次${labelZh} sub-${r.threshold} (${r.value.toFixed(2)} s)`,
    };
  });
}

export const SUB_X_MILESTONES: SubMilestone[] = annotateSub(data.subMilestonesSingle, 'single');
export const SUB_X_AO5: SubMilestone[] = annotateSub(data.subMilestonesAo5, 'ao5');

export { FAMOUS_RECONSTRUCTIONS } from './wr333_reconstructions';
